def to_gregorian_seconds(
      %{std_offset: std_offset, utc_offset: utc_offset, microsecond: {microsecond, _}} = datetime
    ) do
  {days, day_fraction} = datetime |> to_iso_days() |> apply_tz_offset(utc_offset + std_offset)
  seconds_in_day = seconds_from_day_fraction(day_fraction)
  {days * @seconds_per_day + seconds_in_day, microsecond}
end

