       {:ok, tab_map} <- get_xlsx_tab_tids(tids),
       {{:ok, direction_0_stop_ids}, {:ok, direction_1_stop_ids}} <- parse_direction_tabs(tab_map) do
    {:ok, {direction_0_stop_ids, direction_1_stop_ids}}
