def read_anonymous(bucket, path) do
  case HTTPoison.get(anonymous_url(bucket, path)) do
    {:ok, %HTTPoison.Response{status_code: 200, body: binary_data}} -> {:ok, binary_data}
    {:ok, %HTTPoison.Response{status_code: 404}} -> {:error, :missing}
    {_, error_or_failure} -> {:error, error_or_failure}
  end
end

def read_local(bucket, path) do
  path = local_path(bucket, path)

  case File.read(path) do
    {:ok, data} -> {:ok, data}
    {:error, :enoent} -> {:error, :missing}
    {:error, e} -> {:error, e}
  end
end

def read_s3(bucket, path) do
  ExAws.S3.get_object(bucket, path)
  |> ExAws.request()
  |> case do
    {:ok, %{status_code: 200, body: data}} -> {:ok, data}
    {:error, {:http_error, 404, _}} -> {:error, :missing}
    {_, error_or_failure} -> {:error, error_or_failure}
  end
end

