definition:
def count_comments_query do
  from(c in Comment, select: count(c.id), where: c.visibility in ^@public_visibility)
end

def default do
  @default
end

def sessions_for_event_query(event_id) do
  from(s in Session, join: e in Event, on: s.event_id == e.id, where: e.id == ^event_id)
end

def count_participants_query(event_id) do
  from(p in Participant, where: p.event_id == ^event_id)
end

def requests_for_actor_query(actor_id) do
  from(p in Participant, where: p.actor_id == ^actor_id and p.role == ^:not_approved)
end

def participant_by_url_query(url) do
  from(p in Participant, where: p.url == ^url, preload: [:actor, :event])
end

def tags_linked_query(tag1_id, tag2_id) do
  from(tr in TagRelation,
    where: tr.tag_id == ^min(tag1_id, tag2_id) and tr.link_id == ^max(tag1_id, tag2_id)
  )
end

def tag_relation_subquery(tag_id) do
  from(tr in TagRelation,
    select: %{id: tr.tag_id, weight: tr.weight},
    where: tr.link_id == ^tag_id
  )
end

def tag_by_title_query(title) do
  from(t in Tag, where: t.title == ^title, limit: 1)
end

def event_by_uuid_query(uuid) do
  from(e in Event, where: e.uuid == ^uuid)
end

def feed_token_query(token) do
  from(ftk in FeedToken, where: ftk.token == ^token, preload: [:actor, :user])
end

def sessions_for_track_query(track_id) do
  from(s in Session, where: s.track_id == ^track_id)
end

def list_participant_actors_for_event_query(event_id) do
  from(a in Actor, join: p in Participant, on: p.actor_id == a.id, where: p.event_id == ^event_id)
end

def tag_by_slug_query(slug) do
  from(t in Tag, where: t.slug == ^slug)
end

def count_events_query do
  from(e in Event, select: count(e.id))
end

def tags_for_event_query(event_id) do
  from(t in Tag, join: e in "events_tags", on: t.id == e.tag_id, where: e.event_id == ^event_id)
end

def count_local_events_query do
  from(e in Event, select: count(e.id), where: e.local == ^true)
end

def event_by_url_query(url) do
  from(e in Event, where: e.url == ^url)
end

