def maybe_parse(html) do
  Enum.reduce_while(parsers(), %{}, fn parser, acc ->
    Logger.debug("Using #{inspect(parser)} to parse link")

    case parser.parse(html, acc) do
      {:ok, data} -> {:halt, data}
      {:error, _msg} -> {:cont, acc}
    end
  end)
end

def parse(nil) do
  {:error, "No URL provided"}
end
def parse(url) do
  case Cachex.fetch(:rich_media_cache, url, fn _ ->
         case parse_url(url) do
           {:ok, data} -> {:commit, data}
           {:error, error_type, error} -> {:ignore, {error_type, error}}
         end
       end) do
    {status, value} when status in [:ok, :commit] -> {:ok, value}
    {_, {error_type, err}} -> {:error, error_type, err}
  end
rescue
  e -> {:error, "Cachex error: #{inspect(e)}"}
end

