def validate_schema(opts, schema) when is_list(schema) do
  Enum.reduce_while(opts, :ok, fn {key, val}, acc ->
    case Keyword.fetch(schema, key) do
      {:ok, type} ->
        case validate_type(type, key, val) do
          :ok -> {:cont, acc}
          error -> {:halt, error}
        end

      :error ->
        {:halt, unknown_error(key, Keyword.keys(schema))}
    end
  end)
end

def from_string(worker_name) when is_binary(worker_name) do
  module = worker_name |> String.split(".") |> Module.safe_concat()

  if Code.ensure_loaded?(module) && function_exported?(module, :perform, 1) do
    {:ok, module}
  else
    {:error, RuntimeError.exception("module is not a worker: #{inspect(module)}")}
  end
rescue
  ArgumentError -> {:error, RuntimeError.exception("unknown worker: #{worker_name}")}
end

